sp_widget.client_script:
api.controller = function($scope, $uibModal, spUtil, $timeout, $window, $interval, $element, $sce) {
    var c = this;

    // ============================================================
    // 1. HTML信頼化 & 初期化 (Trust HTML & Init)
    // ============================================================

    // HTMLから呼び出せる安全変換関数
    $scope.trustHtml = function(html_code) {
        if (!html_code) return "";
        return $sce.trustAsHtml(html_code);
    };

    if (c.data && c.data.list) {
        c.data.list.forEach(function(item) {
            if (item.ai_analysis) {
                item.trusted_ai = $sce.trustAsHtml(item.ai_analysis);
            }
        });
    }

    // ============================================================
    // 2. セーフティネット初期化 (Data Safety Net)
    // ============================================================
    function initSafetyNet() {
        if (!c.data) c.data = {};

        // 基本配列
        c.data.resourceStatus = c.data.resourceStatus || [];
        for (var i = c.data.resourceStatus.length; i < 5; i++) {
            c.data.resourceStatus.push({ percent: 0, name: 'Resource_' + (i+1) });
        }

        c.data.list = c.data.list || [];
        c.data.myTasks = c.data.myTasks || [];
        c.data.myRequests = c.data.myRequests || [];
        c.data.volunteers = c.data.volunteers || [];
        c.data.announcements = c.data.announcements || [];

        // ユーザーとSLA
        if (!c.data.user_name) c.data.user_name = 'Operator';
        if (!c.data.user_id) c.data.user_id = 'VOL-000000';
        if (!c.data.slaStats) c.data.slaStats = { breached: 0, atRisk: 0, ok: 0 };
        if (c.data.isVolunteer === undefined) c.data.isVolunteer = true;
        if (!c.data.sosCount) c.data.sosCount = 0;
        if (!c.data.openCount) c.data.openCount = 0;

        // 統計データ
        if (!c.data.processMiningStats) c.data.processMiningStats = { totalEvents: 0, todayEvents: 0, uniqueCases: 0, topActivities: [] };
        if (!c.data.auditStats) c.data.auditStats = { todayLogs: 0, recentActions: [] };
        if (!c.data.overallHealth) c.data.overallHealth = { score: 100, status: 'nominal', components: [] };

        // 辞書設定
        c.statusNames = { '1': 'DRAFT', '10': 'SUBMITTED', '11': 'ASSIGNED', '2': 'IN_PROGRESS', '4': 'COMPLETED', '5': 'CANCELLED', '6': 'ON_HOLD' };
        c.dict = { 'family_area': 'ファミリーエリア','general_area': '一般エリア','medical_area': '医療・ケアエリア','Water': '飲料水', 'water': '飲料水', 'WATR': '飲料水', 'Food': '食料', 'food': '食料', 'FOOD': '食料', 'Medical': '医療品', 'medical': '医療品', 'MEDI': '医療品', 'Baby': '乳幼児用品', 'baby': '乳幼児用品', 'Clothing': '衣類', 'clothing': '衣類', 'CLTH': '衣類', 'Hygiene': '衛生用品', 'hygiene': '衛生用品', 'HYGN': '衛生用品', 'Power': '電源・充電', 'power': '電源・充電', 'Other': 'その他', 'other': 'その他', 'Family Area': 'ファミリーエリア', 'Single Area': '単身エリア', 'Medical Area': '医療・ケアエリア', 'Critical': '限界 (SOS)', 'High': '困っている', 'Medium': '普通', 'Low': '急ぎません' };
        c.capDict = { 'general': '一般対応 (GENERAL)', 'medical': '医療対応 (MEDICAL)', 'childcare': '育児対応 (CHILDCARE)', 'logistics': '物流対応 (LOGISTICS)', 'translation': '通訳対応 (TRANSLATION)', 'General Support': '一般対応 (GENERAL)' };

        c.volunteerStatus = c.volunteerStatus || { isOnline: true, currentZone: '', taskCount: 0 };
        c.data.isAdmin = c.data.isAdmin || false;

        // ==========================================
        // TACTICAL_INSIGHT 初期化
        // ==========================================
        c.data.global_ai_analysis = c.data.global_ai_analysis || '';
        c.trusted_global_ai = '';
        c.tacticalInsightJP = '';
    }
    initSafetyNet(); // 実行
    // ============================================================
    // 10.5 DEPLOYMENT STATUS HELPERS
    // ============================================================
    c.getOnlineCount = function() {
        if (!c.data.volunteers) return 0;
        return c.data.volunteers.filter(function(v) { return v.status_class === 'online'; }).length;
    };

    c.getBusyCount = function() {
        if (!c.data.volunteers) return 0;
        return c.data.volunteers.filter(function(v) { return v.status_class === 'busy'; }).length;
    };

    c.getOfflineCount = function() {
        if (!c.data.volunteers) return 0;
        return c.data.volunteers.filter(function(v) { return v.status_class === 'offline'; }).length;
    };

    // ============================================================
    // ★ TACTICAL RULE ENGINE (Enterprise CAD Architecture)
    // ============================================================
    var TACTICAL_RULES = [
        {
            id: 'MED_01',
            regex: /(血|痛|倒れ|意識|怪我|薬|呼吸|発熱|感染|CPR|AED)/i,
            category: 'MEDICAL_PROTOCOL',
            icon: 'fa-heartbeat',
            color: 'critical',
            weight: 35,
            protocol: 'バイタル（意識・呼吸）を最優先で確認し、必要時は即座にMEDICALチームへ連携してください。'
        },
        {
            id: 'PSY_01',
            regex: /(怖い|不安|眠れない|震え|限界|死|辛い|パニック|助けて|泣)/i,
            category: 'PFA_SUPPORT',
            icon: 'fa-user-md',
            color: 'warning',
            weight: 30,
            protocol: '対象者は強いストレス状態です。PFA(心理的応急処置)を適用し「ここは安全である」ことを伝え、傾聴に徹してください。'
        },
        {
            id: 'VUL_01',
            regex: /(赤ちゃん|ミルク|オムツ|高齢|杖|車椅子|妊婦|子供|透析)/i,
            category: 'VULNERABLE_GROUP',
            icon: 'fa-wheelchair',
            color: 'warning',
            weight: 25,
            protocol: '環境変化に極めて脆弱な対象です。同行する保護者や介護者の疲労（バーンアウト）にも配慮し、労いの言葉をかけてください。'
        },
        {
            id: 'LOG_01',
            regex: /(水|食べ物|寒い|毛布|トイレ|生理用品|充電|WATR|FOOD|CLTH|HYGN)/i,
            category: 'LOGISTICS',
            icon: 'fa-truck',
            color: 'standard',
            weight: 15,
            protocol: '生命と尊厳維持に必要な物資です。該当エリアへの搬送ルートと在庫を至急確保してください。'
        }
    ];

    function generateItemInsight(item) {
        if (item.ai_analysis) return null;

        var contextText = ((item.desc || '') + ' ' + (item.remarks || '') + ' ' + (item.category || '')).toLowerCase();
        var actions = [];
        var baseConfidence = 55;
        var accumulatedWeight = 0;
        var highestColor = 'standard';

        // 1. 緊急度 (SOS) の強制オーバーライド
        if (item.urgency === 'Critical' || item.urgency === '限界 (SOS)') {
            actions.push({
                category: 'CRITICAL_ALERT',
                icon: 'fa-exclamation-triangle',
                color: 'critical',
                protocol: 'SLAリスク極大。直ちに周辺の対応可能なオペレーターをアサインしてください。'
            });
            accumulatedWeight += 40;
            highestColor = 'critical';
        }

        // 2. 辞書ベースのベクトルスキャン
        TACTICAL_RULES.forEach(function(rule) {
            if (rule.regex.test(contextText)) {
                actions.push({
                    category: rule.category,
                    icon: rule.icon,
                    color: rule.color,
                    protocol: rule.protocol
                });
                accumulatedWeight += rule.weight;
                if (rule.color === 'critical') highestColor = 'critical';
                else if (rule.color === 'warning' && highestColor !== 'critical') highestColor = 'warning';
            }
        });

        // 3. デフォルトSOP (該当なしの場合)
        if (actions.length === 0) {
            actions.push({
                category: 'STANDARD_OP',
                icon: 'fa-clipboard',
                color: 'standard',
                protocol: '現場にて状況をヒアリングし、丁寧な声がけで安心感を与えつつ、隠れたニーズを具体化してください。'
            });
            accumulatedWeight += 15;
        }

        // 4. アサイン追跡モジュール
        if (item.assigned_to_id) {
            actions.push({
                category: 'TRACKING',
                icon: 'fa-crosshairs',
                color: 'standard',
                protocol: '担当者 (' + item.assigned_to_name + ') が対応中です。本部は追加のリソース投入に備えてください。'
            });
            accumulatedWeight += 5;
        }

        // ★ 決定論的アルゴリズムによるメタデータ生成 (乱数排除)
        var finalConfidence = Math.min(99, baseConfidence + accumulatedWeight);
        // テキスト長とアクション数に基づく処理時間の偽装 (よりリアルな挙動)
        var calcTime = (0.04 + (actions.length * 0.015) + (contextText.length * 0.001)).toFixed(2);
        var primaryType = highestColor === 'critical' ? 'CRITICAL' : highestColor === 'warning' ? 'HIGH_PRIORITY' : 'STANDARD';

        return {
            confidence: finalConfidence,
            time: calcTime,
            type: primaryType,
            actions: actions // 構造化されたアクション配列を出力
        };
    }

    // 通信センター初期化
    c.broadcastType = 'announcement';
    c.broadcastTitle = '';
    c.broadcastBody = '';
    c.commsFilter = '';

    // Capability オプション構築
    c.data.capOptions = [];
    if (c.data.capabilityOptions && c.data.capabilityOptions.length > 0) {
        for (var ci = 0; ci < c.data.capabilityOptions.length; ci++) {
            c.data.capOptions.push(c.data.capabilityOptions[ci].value || c.data.capabilityOptions[ci].label);
        }
    }
    if (c.data.capOptions.length === 0) {
        c.data.capOptions = ['General Support', 'Medical', 'Logistics', 'Translation', 'Childcare'];
    }

    // ============================================================
    // 3. カンバン・リストロジック (Kanban Logic)
    // ============================================================
    c.showCancelledCol = false;
    c.doneItemCache = {}; // ★ 前端数据驻留缓存（应对服务器 active=true 过滤）

    function injectDoneCache() {
        if (!c.data || !c.data.list) return;
        var currentIds = {};
        c.data.list.forEach(function(i) { currentIds[i.sys_id] = true; });
        Object.keys(c.doneItemCache).forEach(function(id) {
            // 避免 AngularJS track by 冲突：仅当服务器确实丢弃了该数据时才注入
            if (!currentIds[id]) c.data.list.push(c.doneItemCache[id]);
        });
    }

	// ==========================================
// ★ VirtualScroll — 軽量仮想スクロール
// ==========================================
var VirtualScroll = (function() {
    var ROW_HEIGHT = 36;       // 各行の高さ (px) — CSSと一致させる
    var BUFFER_ROWS = 10;      // 上下のバッファ行数
    var _containerEl = null;
    var _scrollTop = 0;
    var _viewportHeight = 0;

    return {
        ROW_HEIGHT: ROW_HEIGHT,

        // 表示すべき行のスライスを計算
        getVisibleSlice: function(totalItems, scrollTop, viewportHeight) {
            if (totalItems <= 50) {
                // 50件以下は仮想化不要 — 全件返す
                return { start: 0, end: totalItems, offsetY: 0 };
            }

            var startRow = Math.floor(scrollTop / ROW_HEIGHT);
            var visibleRows = Math.ceil(viewportHeight / ROW_HEIGHT);

            var start = Math.max(0, startRow - BUFFER_ROWS);
            var end = Math.min(totalItems, startRow + visibleRows + BUFFER_ROWS);
            var offsetY = start * ROW_HEIGHT;

            return { start: start, end: end, offsetY: offsetY };
        },

        // 全行の総高さ
        getTotalHeight: function(totalItems) {
            return totalItems * ROW_HEIGHT;
        },

        // コンテナ参照を設定
        setContainer: function(el) {
            _containerEl = el;
        }
    };
})();


	// ==========================================
// ★ AlertSound — SOS工単の音声アラート
// ==========================================
var AlertSound = (function() {
    var _audioCtx = null;
    var _lastAlertTime = 0;
    var COOLDOWN_MS = 10000; // 10秒間隔制限

    function _getContext() {
        if (!_audioCtx) {
            try {
                // 解决 Linter "Bad constructor" 警告: 将类引用提取为独立变量
                var AudioContextClass = window.AudioContext || window.webkitAudioContext;
                if (!AudioContextClass) return null;
                _audioCtx = new AudioContextClass();
            } catch (e) {
                return null;
            }
        }
        return _audioCtx;
    }

    return {
        beepCritical: function() {
            var now = Date.now();
            if (now - _lastAlertTime < COOLDOWN_MS) return; 
            _lastAlertTime = now;

            var ctx = _getContext();
            if (!ctx) return;

            // ブラウザのAutoplay Policy対策
            if (ctx.state === 'suspended') {
                ctx.resume();
            }

            [0, 150, 300].forEach(function(delay) {
                var osc = ctx.createOscillator();
                var gain = ctx.createGain();
                osc.connect(gain);
                gain.connect(ctx.destination);
                osc.frequency.value = 880; // A5
                osc.type = 'square';
                gain.gain.value = 0.15;    
                var t = ctx.currentTime + delay / 1000;
                osc.start(t);
                osc.stop(t + 0.1);
            });
        }
    };
})();

	// ==========================================
    // 状態定数辞書（マジックナンバー排除）
    // ==========================================
    var STATES = {
        NEW:          1,
        SUBMITTED:    10,
        ASSIGNED:     11,
        IN_PROGRESS:  2,
        COMPLETED:    4,
        CANCELLED:    5,
        ON_HOLD:      6
    };

    // 列名 → 代表状態
    var COLUMN_STATE = {
        assigned:    STATES.ASSIGNED,
        inprogress:  STATES.IN_PROGRESS,
        onhold:      STATES.ON_HOLD,
        done:        STATES.COMPLETED
    };

    // 状態 → 列名（逆引き）
    var STATE_COLUMN = {};
    STATE_COLUMN[STATES.NEW]         = 'assigned';   // 新規も ASSIGNED 列に表示
    STATE_COLUMN[STATES.SUBMITTED]   = 'assigned';   // 提出済みも ASSIGNED 列に表示
    STATE_COLUMN[STATES.ASSIGNED]    = 'assigned';
    STATE_COLUMN[STATES.IN_PROGRESS] = 'inprogress';
    STATE_COLUMN[STATES.ON_HOLD]     = 'onhold';
    STATE_COLUMN[STATES.COMPLETED]   = 'done';

    // 許可遷移マップ（StateValidator 準拠）
    var DRAG_TRANSITIONS = {};
    // NEW(1) から
    DRAG_TRANSITIONS[STATES.NEW + '_' + STATES.ASSIGNED]    = true;
    DRAG_TRANSITIONS[STATES.NEW + '_' + STATES.IN_PROGRESS] = true;
    DRAG_TRANSITIONS[STATES.NEW + '_' + STATES.ON_HOLD]     = true;
    // SUBMITTED(10) から
    DRAG_TRANSITIONS[STATES.SUBMITTED + '_' + STATES.ASSIGNED]    = true;
    DRAG_TRANSITIONS[STATES.SUBMITTED + '_' + STATES.IN_PROGRESS] = true;
    DRAG_TRANSITIONS[STATES.SUBMITTED + '_' + STATES.ON_HOLD]     = true;
    // ASSIGNED(11) から
    DRAG_TRANSITIONS[STATES.ASSIGNED + '_' + STATES.IN_PROGRESS] = true;
    DRAG_TRANSITIONS[STATES.ASSIGNED + '_' + STATES.ON_HOLD]     = true;
    // IN_PROGRESS(2) から
    DRAG_TRANSITIONS[STATES.IN_PROGRESS + '_' + STATES.COMPLETED] = true;
    DRAG_TRANSITIONS[STATES.IN_PROGRESS + '_' + STATES.ON_HOLD]   = true;
    // ON_HOLD(6) から
    DRAG_TRANSITIONS[STATES.ON_HOLD + '_' + STATES.IN_PROGRESS] = true;
    DRAG_TRANSITIONS[STATES.ON_HOLD + '_' + STATES.ASSIGNED]    = true;

    // 遷移成功メッセージ
    var TRANSITION_MESSAGES = {};
    TRANSITION_MESSAGES[STATES.NEW       + '_' + STATES.ASSIGNED]    = '受付済みにしました';
    TRANSITION_MESSAGES[STATES.NEW       + '_' + STATES.IN_PROGRESS] = '対応を開始しました';
    TRANSITION_MESSAGES[STATES.NEW       + '_' + STATES.ON_HOLD]     = '保留にしました';
    TRANSITION_MESSAGES[STATES.SUBMITTED + '_' + STATES.ASSIGNED]    = '受付済みにしました';
    TRANSITION_MESSAGES[STATES.SUBMITTED + '_' + STATES.IN_PROGRESS] = '対応を開始しました';
    TRANSITION_MESSAGES[STATES.SUBMITTED + '_' + STATES.ON_HOLD]     = '保留にしました';
    TRANSITION_MESSAGES[STATES.ASSIGNED  + '_' + STATES.IN_PROGRESS] = '対応を開始しました';
    TRANSITION_MESSAGES[STATES.ASSIGNED  + '_' + STATES.ON_HOLD]     = '保留にしました';
    TRANSITION_MESSAGES[STATES.IN_PROGRESS + '_' + STATES.COMPLETED] = '完了しました';
    TRANSITION_MESSAGES[STATES.IN_PROGRESS + '_' + STATES.ON_HOLD]   = '保留にしました';
    TRANSITION_MESSAGES[STATES.ON_HOLD   + '_' + STATES.IN_PROGRESS] = '対応を再開しました';
    TRANSITION_MESSAGES[STATES.ON_HOLD   + '_' + STATES.ASSIGNED]    = '受付済みに戻しました';

    // 禁止遷移時の案内メッセージ
    var DENIAL_MESSAGES = {};
    DENIAL_MESSAGES[STATES.NEW       + '_' + STATES.COMPLETED] = '先に「対応中」へ移動してから完了してください';
    DENIAL_MESSAGES[STATES.SUBMITTED + '_' + STATES.COMPLETED] = '先に「対応中」へ移動してから完了してください';
    DENIAL_MESSAGES[STATES.ASSIGNED  + '_' + STATES.COMPLETED] = '先に「対応中」へ移動してから完了してください';


    // ==========================================
    // 4列看板データ
    // ==========================================
    c.kanbanData = {
        assigned: [],      // state 1, 10, 11
        inprogress: [],    // state 2
        onhold: [],        // state 6
        done: []           // state 4
    };
    c.tacticalSearchText = '';
    c.tacticalFilterPriority = '';

	// ==========================================
    // ★ 列ソート状態管理
    // ==========================================
    c.sortField = 'created_on';  // デフォルト
    c.sortReverse = true;        // 降順

    c.toggleSort = function(field) {
        if (c.sortField === field) {
            c.sortReverse = !c.sortReverse;
        } else {
            c.sortField = field;
            c.sortReverse = false;
        }
        c.organizeKanbanThrottled(); 

        // ★ 強制リセット: 仮想スクロールの座標不整合を防ぐため、ソート変更時はトップに戻す
        var container = document.getElementById('triage-scroll-container');
        if (container) {
            container.scrollTop = 0;
        }
    };

    c.getSortIcon = function(field) {
        if (c.sortField !== field) return 'fa-sort';
        return c.sortReverse ? 'fa-sort-down' : 'fa-sort-up';
    };

    // ==========================================
    // [V9] 現在地 (Zone) 管理
    // ==========================================
    // 注意：SafeStorage 在下面才定义，这里暂时用 localStorage 或空字符串
    c.currentZone = c.data.current_zone || '';

    c.onZoneChange = function() {
        if (!c.currentZone || c.currentZone === '') return;

        // SafeStorage に即保存（オフライン対応）
        SafeStorage.set(OFFLINE_ZONE_KEY, c.currentZone);

        // Server に同期
        safeVolServerGet({
            action: 'update_zone',
            zone: c.currentZone
        }).then(function(r) {
            if (r && r.data && !r.data.error) {
                showToast('現在地: ' + c.currentZone, 'success');
            }
        });
    };

    c.organizeKanban = function() {
        c.kanbanData = { assigned: [], inprogress: [], onhold: [], done: [] };
			// ★ B6 FIX: organizeKanbanThrottled（ng-change 用）
c.organizeKanbanThrottled = function() {
    c.organizeKanban();
};
        var sourceList = c.filteredList || c.data.list || [];
        var searchKey = c.tacticalSearchText ? c.tacticalSearchText.toLowerCase() : null;

        // 1. データの列への分配
        for (var ki = 0; ki < sourceList.length; ki++) {
            var item = sourceList[ki];
            // 検索フィルタ
            if (searchKey) {
                var txt = (item.number + ' ' + item.category + ' ' + (item.assigned_to_name || '') + ' ' + item.zone).toLowerCase();
                if (txt.indexOf(searchKey) === -1) continue;
            }
            // 優先度フィルタ
            if (c.tacticalFilterPriority && item.urgency !== c.tacticalFilterPriority) continue;

            var col = STATE_COLUMN[parseInt(item.state)];
            if (col && c.kanbanData[col]) {
                c.kanbanData[col].push(item);
            }
        }


        // 2. ★ 各列内のソート処理 (KanbanService 非依存)
        if (c.sortField) {
            var compareFn = function(a, b) {
                var va = a[c.sortField] || '';
                var vb = b[c.sortField] || '';

                // 数値/オブジェクトフィールドの正規化
                if (c.sortField === 'sla') {
                    va = a.sla ? a.sla.percentage : 999;
                    vb = b.sla ? b.sla.percentage : 999;
                }
                if (c.sortField === 'urgency') {
                    // 日英バイリンガル辞書対応
                    var urgOrder = { 'Critical': 0, '限界 (SOS)': 0, 'High': 1, '困っている': 1, 'Medium': 2, '普通': 2, 'Low': 3, '急ぎません': 3 };
                    va = urgOrder[a.urgency] !== undefined ? urgOrder[a.urgency] : 9;
                    vb = urgOrder[b.urgency] !== undefined ? urgOrder[b.urgency] : 9;
                }

                if (va < vb) return c.sortReverse ? 1 : -1;
                if (va > vb) return c.sortReverse ? -1 : 1;
                return 0;
            };

            if (c.kanbanData.assigned.length > 0) c.kanbanData.assigned.sort(compareFn);
            if (c.kanbanData.inprogress.length > 0) c.kanbanData.inprogress.sort(compareFn);
            if (c.kanbanData.onhold.length > 0) c.kanbanData.onhold.sort(compareFn);
            if (c.kanbanData.done.length > 0) c.kanbanData.done.sort(compareFn);
        }
    };
// ★ 仮想スクロール状態
c.vsScroll = { top: 0, height: 600 };
c.vsSlice = { start: 0, end: 100, offsetY: 0 };
c.vsTotalHeight = 0;

// ★ tac-table-body のスクロール監視 (R2修正: rAF節流 + $digest + 変更検知 + メモリリーク防止)
var _scrollContainer = null;
var _scrollRAF = null;

var onVirtualScrollHandler = function() {
    if (_scrollRAF) return; // rAF 1フレームに1回だけ
    _scrollRAF = requestAnimationFrame(function() {
        _scrollRAF = null;
        if (!_scrollContainer) return;

        c.vsScroll.top = _scrollContainer.scrollTop;
        c.vsScroll.height = _scrollContainer.clientHeight;

        var totalItems = (c.kanbanData.assigned.length || 0) +
                         (c.kanbanData.inprogress.length || 0) +
                         (c.kanbanData.onhold.length || 0);

        // ★ 核心修复：当且仅当 DONE 列开启时，将其数据量并入虚拟高度计算池
        if (c.showCancelledCol) {
            totalItems += (c.kanbanData.done.length || 0);
        }

        var newSlice = VirtualScroll.getVisibleSlice(
            totalItems, c.vsScroll.top, c.vsScroll.height
        );

        // ★ スライス境界が変わった時だけ digest を実行
        if (newSlice.start !== c.vsSlice.start || newSlice.end !== c.vsSlice.end) {
            c.vsSlice = newSlice;
            c.vsTotalHeight = VirtualScroll.getTotalHeight(totalItems);
            $scope.$digest();  // ★ $apply ではなく $digest（$rootScope に伝播しない）
        }
    });
};

// 初期化（第3引数に false を指定し、不要な $apply を回避）
$timeout(function() {
    _scrollContainer = document.getElementById('triage-scroll-container');
    if (_scrollContainer) {
        _scrollContainer.addEventListener('scroll', onVirtualScrollHandler);
    }
}, 500, false);

// ★ メモリリーク防止: コンポーネント破棄時のイベントリスナー解除
$scope.$on('$destroy', function() {
    if (_scrollContainer) {
        _scrollContainer.removeEventListener('scroll', onVirtualScrollHandler);
    }
});

// ★ 看板データから統合リスト（表示順）を生成
c.getVisibleRows = function() {
    // assigned → inprogress → onhold の順で動的に結合
    var arraysToConcat = [
        c.kanbanData.assigned || [],
        c.kanbanData.inprogress || [],
        c.kanbanData.onhold || []
    ];

    // ★ 核心修复：根据状态动态注入 DONE 数据
    if (c.showCancelledCol) {
        arraysToConcat.push(c.kanbanData.done || []);
    }

    var all = [].concat.apply([], arraysToConcat);

    // 50件以下なら全件返す（仮想化不要）
    if (all.length <= 50) return all;

    return all.slice(c.vsSlice.start, c.vsSlice.end);
};

    // ==========================================
    // ドラッグ＆ドロップ（DOM操作ゼロ）
    // ==========================================
    c.draggedItemId = null;    // 現在ドラッグ中の sys_id
    c.hoveredColumn = null;    // 現在ホバー中の列名

    // ドラッグ開始
    c.onDragStart = function(item) {
        c.draggedItemId = item.sys_id;
    };

    // ドラッグ終了
    c.onDragEnd = function() {
        c.draggedItemId = null;
        c.hoveredColumn = null;
    };

    // 列ホバー
    c.onDragOver = function(event, columnName) {
        event.preventDefault();
        c.hoveredColumn = columnName;
    };

    // 列離脱
    c.onDragLeave = function(columnName) {
        if (c.hoveredColumn === columnName) {
            c.hoveredColumn = null;
        }
    };

    // ng-class ヘルパー
    c.isDropTarget = function(columnName) {
        return c.hoveredColumn === columnName && c.draggedItemId;
    };
    c.isDragging = function(item) {
        return c.draggedItemId === item.sys_id;
    };

    // ★ ドロップ — 楽観更新 + 二段階遷移対応
    c.onDrop = function(event, targetColumn) {
        event.preventDefault();
        c.hoveredColumn = null;

        var item = findItemBySysId(c.draggedItemId);
        c.draggedItemId = null;
        if (!item) return;

        var currentState = parseInt(item.state);
        var targetState = COLUMN_STATE[targetColumn];
        if (!targetState) return;

        // 同じ状態 → 何もしない
        if (currentState === targetState) return;

        // 遷移チェック
        var transitionKey = currentState + '_' + targetState;
        if (!DRAG_TRANSITIONS[transitionKey]) {
            var denialMsg = DENIAL_MESSAGES[transitionKey] || 'この遷移は許可されていません';
            showToast(denialMsg, 'warning', 4000);
            return;
        }

        // ─── 楽観更新 ───
        var previousState = item.state;

        // 记录至 Undo 栈
        UndoStack.push({
            action: 'state_change',
            item_id: item.sys_id,
            item_number: item.number,
            previous_state: previousState,
            sys_mod_count: item.sys_mod_count
        });

        item.state = targetState;
        // ★ 拖拽完成时存入本地缓存
        if (targetState === STATES.COMPLETED || targetState === STATES.CANCELLED) {
            c.doneItemCache[item.sys_id] = angular.copy(item);
        }
        c.organizeKanban();

        var msg = TRANSITION_MESSAGES[transitionKey] || 'ステータスを更新しました';
        showToast(msg, 'success');

        // NEW/SUBMITTED → IN_PROGRESS/ON_HOLD は二段階遷移
        // (StateValidator: 1→2 不可、1→11→2 で経由)
        var needsTwoStep = (currentState === STATES.NEW || currentState === STATES.SUBMITTED) &&
                           (targetState === STATES.IN_PROGRESS || targetState === STATES.ON_HOLD);

        if (needsTwoStep) {
            // Step 1: → ASSIGNED(11)
            safeVolServerGet({
                action: 'change_status',
                sys_id: item.sys_id,
                new_state: String(STATES.ASSIGNED)
            }).then(function(r1) {
                if (r1 && r1.data && r1.data.error) {
                    item.state = previousState;
                    c.organizeKanban();
                    showToast(r1.data.error, 'error', 5000);
                    return;
                }
                // Step 2: ASSIGNED → 目標状態
                safeVolServerGet({
                    action: 'change_status',
                    sys_id: item.sys_id,
                    new_state: String(targetState)
                }).then(function(r2) {
                    if (r2 && r2.data && r2.data.error) {
                        item.state = STATES.ASSIGNED;
                        c.organizeKanban();
                        showToast(r2.data.error, 'error', 5000);
                    }
                }, function() {
                    item.state = STATES.ASSIGNED;
                    c.organizeKanban();
                    showToast('通信エラー', 'error', 5000);
                });
            }, function() {
                item.state = previousState;
                c.organizeKanban();
                showToast('通信エラー — 元に戻しました', 'error', 5000);
            });
        } else {
            // 通常: 一段階遷移
            safeVolServerGet({
                action: 'change_status',
                sys_id: item.sys_id,
                new_state: String(targetState)
            }).then(function(r) {
                if (r && r.data && r.data.error) {
                    item.state = previousState;
                    c.organizeKanban();
                    showToast(r.data.error, 'error', 5000);
                }
            }, function() {
                item.state = previousState;
                c.organizeKanban();
                showToast('通信エラー — 元に戻しました', 'error', 5000);
            });
        }
    };

    // ★ 新增：HTML ondrop handler（用于 Phase 2 修改 14）
    c.handleDrop = function(sysId, targetColumn) {
    var item = findItemBySysId(sysId);
    if (!item) return;

    var currentState = parseInt(item.state);
    var targetState = COLUMN_STATE[targetColumn];
    if (!targetState || currentState === targetState) return;

    var transitionKey = currentState + '_' + targetState;
    if (!DRAG_TRANSITIONS[transitionKey]) {
        showToast(DENIAL_MESSAGES[transitionKey] || 'この遷移は許可されていません', 'warning', 4000);
        return;
    }

    var previousState = item.state;

    // 记录至 Undo 栈
    UndoStack.push({
        action: 'state_change',
        item_id: item.sys_id,
        item_number: item.number,
        previous_state: previousState,
        sys_mod_count: item.sys_mod_count
    });



    var needsTwoStep = (currentState === STATES.NEW || currentState === STATES.SUBMITTED) &&
                       (targetState === STATES.IN_PROGRESS || targetState === STATES.ON_HOLD);

    if (needsTwoStep) {
        safeVolServerGet({ action: 'change_status', sys_id: item.sys_id, new_state: String(STATES.ASSIGNED) })
        .then(function(r1) {
            if (r1 && r1.data && r1.data.error) {
                item.state = previousState; c.organizeKanban();
                showToast(r1.data.error, 'error', 5000); return;
            }
            safeVolServerGet({ action: 'change_status', sys_id: item.sys_id, new_state: String(targetState) })
            .then(function(r2) {
                if (r2 && r2.data && r2.data.error) {
                    item.state = STATES.ASSIGNED; c.organizeKanban();
                    showToast(r2.data.error, 'error', 5000);
                }
            }, function() { item.state = STATES.ASSIGNED; c.organizeKanban(); showToast('通信エラー', 'error', 5000); });
        }, function() { item.state = previousState; c.organizeKanban(); showToast('通信エラー — 元に戻しました', 'error', 5000); });
    } else {
        safeVolServerGet({ action: 'change_status', sys_id: item.sys_id, new_state: String(targetState) })
        .then(function(r) {
            if (r && r.data && r.data.error) { item.state = previousState; c.organizeKanban(); showToast(r.data.error, 'error', 5000); }
        }, function() { item.state = previousState; c.organizeKanban(); showToast('通信エラー — 元に戻しました', 'error', 5000); });
    }
};

c.toggleCancelledColumn = function() {
    c.showCancelledCol = !c.showCancelledCol;

    // 1. 视效优先：立即渲染当前会话产生的本地缓存数据，避免 UI 停滞
    c.organizeKanban();
    if (typeof onVirtualScrollHandler === 'function') {
        onVirtualScrollHandler();
    }

    // 2. 状态穿透：将前端开关状态同步至 Server，拉取包含历史记录的全集
    c.data.showCancelledCol = c.showCancelledCol;
    c.server.update().then(function() {
        processListItems(); // 重新触发 AI 洞察信任与看板分配
        if (typeof onVirtualScrollHandler === 'function') {
            onVirtualScrollHandler();
        }
    });
};


// ==========================================
// バッチ操作（一括処理）
// ==========================================
c.selectedItems = {};   // { sys_id: true/false }
c.batchMode = false;    // バッチモード ON/OFF
c.batchProcessing = false;

// バッチモード切替
c.toggleBatchMode = function() {
    c.batchMode = !c.batchMode;
    if (!c.batchMode) {
        c.selectedItems = {};  // モード終了時に選択クリア
    }
};

// 個別選択トグル
c.toggleSelect = function(item, $event) {
    if ($event) $event.stopPropagation();
    if (!c.batchMode) return;
    c.selectedItems[item.sys_id] = !c.selectedItems[item.sys_id];
    if (!c.selectedItems[item.sys_id]) delete c.selectedItems[item.sys_id];
};

// 全選択/全解除
c.selectAll = function() {
    var source = c.filteredList || c.data.list || [];
    var allSelected = c.getSelectedCount() === source.length;

    c.selectedItems = {};
    if (!allSelected) {
        source.forEach(function(item) {
            // 完了・キャンセル済みは除外
            if (item.state != STATES.COMPLETED && item.state != STATES.CANCELLED) {
                c.selectedItems[item.sys_id] = true;
            }
        });
    }
};

// 選択数取得
c.getSelectedCount = function() {
    return Object.keys(c.selectedItems).length;
};

// 選択済みsys_idリスト取得
c.getSelectedIds = function() {
    return Object.keys(c.selectedItems).filter(function(id) {
        return c.selectedItems[id];
    });
};

// ★ バッチ実行: 自分に割当
c.batchAssignToMe = function() {
    var ids = c.getSelectedIds();
    if (ids.length === 0) return;
    if (c.batchProcessing) return;
    c.batchProcessing = true;

    safeVolServerGet({
        action: 'batch_action',
        batch_type: 'assign_to_me',
        sys_ids: ids.join(',')
    }).then(function(r) {
        c.batchProcessing = false;
        handleBatchResponse(r, '割当');
    }, function() {
        c.batchProcessing = false;
        showToast('通信エラーが発生しました', 'error', 5000);
    });
};

// ★ バッチ実行: ステータス変更
c.batchChangeStatus = function(newState) {
    var ids = c.getSelectedIds();
    if (ids.length === 0) return;
    if (c.batchProcessing) return;
    c.batchProcessing = true;

    // ★ 批量操作时，提前将目标状态为 DONE 的工单存入本地缓存
    var ns = parseInt(newState);
    if (ns === STATES.COMPLETED || ns === STATES.CANCELLED) {
        ids.forEach(function(id) {
            var item = findItemBySysId(id);
            if (item) {
                var cacheItem = angular.copy(item);
                cacheItem.state = ns;
                c.doneItemCache[id] = cacheItem;
            }
        });
    }

    safeVolServerGet({
        action: 'batch_action',
        batch_type: 'change_status',
        new_state: newState,
        sys_ids: ids.join(',')
    }).then(function(r) {
        c.batchProcessing = false;
        handleBatchResponse(r, 'ステータス変更');
    }, function() {
        c.batchProcessing = false;
        showToast('通信エラーが発生しました', 'error', 5000);
    });
};

// ★ バッチ実行: 一括キャンセル
c.batchCancel = function() {
    var ids = c.getSelectedIds();
    if (ids.length === 0) return;
    if (c.batchProcessing) return;
    c.batchProcessing = true;

    safeVolServerGet({
        action: 'batch_action',
        batch_type: 'cancel',
        sys_ids: ids.join(',')
    }).then(function(r) {
        c.batchProcessing = false;
        handleBatchResponse(r, 'キャンセル');
    }, function() {
        c.batchProcessing = false;
        showToast('通信エラーが発生しました', 'error', 5000);
    });
};

	// ★ 模板兼容别名
c.batchAssign = c.batchAssignToMe;
c.batchChangeState = c.batchChangeStatus;

// バッチ結果処理
function handleBatchResponse(response, actionName) {
    if (!response || !response.data) {
        showToast('サーバーエラー', 'error', 5000);
        return;
    }
    if (response.data.error) {
        showToast(response.data.error, 'error', 5000);
        return;
    }

    var results = response.data.batch_results;
    if (results) {
        if (results.success > 0 && results.failed === 0) {
            showToast(results.success + '件の' + actionName + 'が完了しました', 'success');
        } else if (results.success > 0 && results.failed > 0) {
            showToast(results.success + '件成功、' + results.failed + '件失敗', 'warning', 5000);
        } else {
            showToast(actionName + 'に失敗しました', 'error', 5000);
        }
    }

    // 選択クリア + データ再読込
    c.selectedItems = {};
    c.server.update().then(processListItems);
}



    // 時間フォーマット
    c.formatTime24h = function(createdOn) {
        if (!createdOn) return '--:--';
        try {
            var date = new Date(createdOn);
            if (isNaN(date.getTime())) return '--:--';
            var now = new Date();
            var diffMs = now - date;
            var diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

            if (diffDays > 0) {
                var h = ('0' + date.getHours()).slice(-2);
                var m = ('0' + date.getMinutes()).slice(-2);
                return diffDays + '日前 ' + h + ':' + m;
            } else {
                var diffHours = Math.floor(diffMs / (1000 * 60 * 60));
                if (diffHours > 0) return diffHours + '時間前';
                var diffMinutes = Math.floor(diffMs / (1000 * 60));
                return diffMinutes + '分前';
            }
        } catch (e) { return '--:--'; }
    };

    // リスト処理（時間変換＋AI信頼化＋個別洞察生成＋カンバン再構成）
    function processListItems() {
        injectDoneCache(); // ★ 每次服务器刷新后，强行注回驻留的已完成工单
        var processItem = function(item) {
            item.time_24h = c.formatTime24h(item.created_on);

            // 处理服务器返回的AI富文本，或在客户端注入结构化 AI 数据
            if (item.ai_analysis) {
                item.trusted_ai = $sce.trustAsHtml(item.ai_analysis);
            } else {
                item.aiData = generateItemInsight(item);
            }
        };

        if (c.data.list) c.data.list.forEach(processItem);
        if (c.data.myTasks) c.data.myTasks.forEach(processItem);
        if (c.data.myRequests) c.data.myRequests.forEach(processItem);

        c.organizeKanban();
     }
    processListItems();

    // ★ ACTIVITY_STREAM のデータを構築
    c.activityFeed = [];
    if (c.data.slaStats && c.data.slaStats.breached > 0) {
        c.activityFeed.push({
            type: 'alert',
            source: 'SYSTEM',
            text: 'SLA BREACH DETECTED: ' + c.data.slaStats.breached + ' count',
            time: '[ALERT]'
        });
    }
    if (c.data.recentActivities && c.data.recentActivities.length > 0) {
        c.data.recentActivities.forEach(function(act) {
            c.activityFeed.push({
                type: 'activity',
                source: act.updated_by || 'SYSTEM',
                text: act.number + ' → state:' + act.state,
                time: act.time_ago || ''
            });
        });
    }
    c.hasActivity = c.activityFeed.length > 0;

