// ステータスの表示クラスを返す
// draft       → グレー（下書き）
// submitted   → グリーン（提出済み＝安全確認済み）
// assigned    → ブルー
// In Progress → イエロー
// Completed   → グリーン
// Cancelled   → グレー
// On Hold     → オレンジ
c.getHeartbeatStatusClass = function(stateValue) {
    // 数字→文字列に正規化
    var normalize = {
        '100': 'draft', '10': 'draft', '1': 'draft',
        '200': 'submitted', '20': 'submitted', '2': 'submitted',
        '300': 'assigned', '30': 'assigned', '3': 'assigned',
        '400': 'In Progress', '40': 'In Progress', '4': 'In Progress',
        '500': 'Completed', '50': 'Completed', '5': 'Completed',
        '600': 'Cancelled', '60': 'Cancelled', '6': 'Cancelled',
        '700': 'On Hold', '70': 'On Hold', '7': 'On Hold'
    };
    var s = normalize[stateValue] || stateValue;

    switch (s) {
        case 'submitted':   return 'hb-status-safe';
        case 'Completed':   return 'hb-status-safe';
        case 'assigned':    return 'hb-status-assigned';
        case 'In Progress': return 'hb-status-progress';
        case 'On Hold':     return 'hb-status-warning';
        case 'Cancelled':   return 'hb-status-cancelled';
        case 'draft':       return 'hb-status-draft';
        default:            return 'hb-status-draft';
    }
};

