    var _searchDebounceTimer = null;
    c.onSearchInput = function() {
        if (_searchDebounceTimer) {
            $timeout.cancel(_searchDebounceTimer);
        }

        // 第3引数を false に設定し、全局の $apply 汚染を遮断
